from django.db.models import Q
from django.contrib.postgres.search import SearchVector, SearchQuery

def search(query):
    # Combine full-text search with partial matching for accuracy
    # Use full-text for performance, fallback to ILIKE for partial matches
    fts_results = Document.objects.annotate(
        search=SearchVector('content'),
    ).filter(search=SearchQuery(query))

    # Also check for substring matches not caught by FTS
    partial_results = Document.objects.filter(
        content__icontains=query
    ).exclude(id__in=[r.id for r in fts_results])

    return list(fts_results) + list(partial_results)
